  });
});
```

#### 5. Hardcoded Port
Hardcoding `3000` prevents flexible deployments and is a security smell in production configs:
```js
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
